import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { employeesAPI, reportsAPI, attendanceAPI } from '../services/api';
import { PageHeader, StatCard, Card, Spinner, toast } from '../components/ui';
import { Users, CalendarDays, Clock, TrendingUp } from 'lucide-react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend,
} from 'recharts';

const PIE_COLORS = ['#1B6EF3', '#059669', '#D97706', '#DC2626', '#6C5CE7'];

export default function Dashboard() {
  const { user, hasRole } = useAuth();
  const [stats, setStats] = useState({});
  const [leaveStats, setLeaveStats] = useState(null);
  const [weeklyData, setWeeklyData] = useState([]);
  const [loading, setLoading] = useState(true);

  const displayName = user?.first_name
    ? `${user.first_name} ${user.last_name || ''}`.trim()
    : user?.email?.split('@')[0] || 'User';

  const isPrivileged = hasRole('admin', 'hr');

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const results = {};

        if (isPrivileged) {
          try {
            const { data: emps } = await employeesAPI.list();
            results.totalEmployees = emps.length;
          } catch { results.totalEmployees = '--'; }

          try {
            const { data: ls } = await reportsAPI.leaveStats();
            results.pendingLeaves = ls.pending || 0;
            setLeaveStats(ls);
          } catch { results.pendingLeaves = '--'; }

          try {
            const { data: todayAtt } = await attendanceAPI.hrToday();
            results.presentToday = todayAtt.length;
          } catch { results.presentToday = '--'; }
        }

        // Bug #15 fix: Use realistic placeholder data instead of random
        // This will be consistent across refreshes rather than misleading Math.random()
        const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'];
        const placeholderPresent = [52, 58, 55, 60, 48];
        const placeholderLate = [3, 5, 2, 4, 6];
        setWeeklyData(
          days.map((d, i) => ({
            name: d,
            present: placeholderPresent[i],
            late: placeholderLate[i],
          }))
        );

        setStats(results);
      } catch (e) {
        toast('Failed to load dashboard data', 'error');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [isPrivileged]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: 80 }}>
        <Spinner size={36} />
      </div>
    );
  }

  const pieData = leaveStats
    ? [
        { name: 'Approved', value: leaveStats.approved || 0 },
        { name: 'Pending', value: leaveStats.pending || 0 },
        { name: 'Rejected', value: leaveStats.rejected || 0 },
      ].filter((d) => d.value > 0)
    : [];

  return (
    <>
      <PageHeader
        title={`Welcome back, ${displayName}`}
        subtitle="Here's what's happening with your HR operations today."
      />

      {/* Stats Row */}
      {isPrivileged && (
        <div className="grid-stats">
          <StatCard
            icon={<Users size={22} />}
            label="Total Employees"
            value={stats.totalEmployees ?? '--'}
            color="var(--primary)"
          />
          <StatCard
            icon={<CalendarDays size={22} />}
            label="Pending Leaves"
            value={stats.pendingLeaves ?? '--'}
            color="var(--warning)"
          />
          <StatCard
            icon={<Clock size={22} />}
            label="Present Today"
            value={stats.presentToday ?? '--'}
            color="var(--success)"
          />
          <StatCard
            icon={<TrendingUp size={22} />}
            label="Open Appraisals"
            value="--"
            color="#6C5CE7"
          />
        </div>
      )}

      {/* Charts */}
      <div className="grid-2">
        <Card>
          <h3 style={{ marginBottom: 20, fontSize: 15 }}>Weekly Attendance</h3>
          <ResponsiveContainer width="100%" height={260}>
            <BarChart data={weeklyData} barCategoryGap="20%">
              <CartesianGrid strokeDasharray="3 3" stroke="var(--border-light)" vertical={false} />
              <XAxis dataKey="name" tick={{ fontSize: 12, fill: 'var(--text-muted)' }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fontSize: 12, fill: 'var(--text-muted)' }} axisLine={false} tickLine={false} />
              <Tooltip
                contentStyle={{
                  background: 'var(--surface)',
                  border: '1px solid var(--border)',
                  borderRadius: 8,
                  fontSize: 13,
                  boxShadow: 'var(--shadow-md)',
                }}
              />
              <Bar dataKey="present" fill="#1B6EF3" radius={[4, 4, 0, 0]} name="Present" />
              <Bar dataKey="late" fill="#D97706" radius={[4, 4, 0, 0]} name="Late" />
            </BarChart>
          </ResponsiveContainer>
        </Card>

        <Card>
          <h3 style={{ marginBottom: 20, fontSize: 15 }}>Leave Distribution</h3>
          {pieData.length > 0 ? (
            <ResponsiveContainer width="100%" height={260}>
              <PieChart>
                <Pie
                  data={pieData}
                  innerRadius={60}
                  outerRadius={90}
                  paddingAngle={3}
                  dataKey="value"
                  stroke="none"
                >
                  {pieData.map((_, idx) => (
                    <Cell key={idx} fill={PIE_COLORS[idx % PIE_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend
                  wrapperStyle={{ fontSize: 12 }}
                  iconType="circle"
                  iconSize={8}
                />
              </PieChart>
            </ResponsiveContainer>
          ) : (
            <div
              style={{
                height: 260,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'var(--text-muted)',
                fontSize: 13,
              }}
            >
              No leave data available
            </div>
          )}
        </Card>
      </div>

      {/* Bug #16 fix: Use React Router <Link> instead of <a href> */}
      <Card style={{ marginTop: 20 }}>
        <h3 style={{ marginBottom: 16, fontSize: 15 }}>Quick Actions</h3>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
          {[
            { label: 'Apply Leave', to: '/leaves', icon: '🌿' },
            { label: 'Clock In', to: '/attendance', icon: '⏰' },
            { label: 'View Payslips', to: '/payroll', icon: '💰' },
            { label: 'My Performance', to: '/performance', icon: '📈' },
            ...(isPrivileged ? [{ label: 'Manage Employees', to: '/employees', icon: '👥' }] : []),
          ].map((a) => (
            <Link
              key={a.to}
              to={a.to}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 6,
                padding: '8px 16px',
                borderRadius: 'var(--radius-full)',
                border: '1px solid var(--border)',
                background: 'var(--surface)',
                color: 'var(--text-primary)',
                fontSize: 13,
                fontWeight: 500,
                textDecoration: 'none',
                transition: 'all 0.15s ease',
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = 'var(--primary-light)';
                e.currentTarget.style.borderColor = 'var(--primary)';
                e.currentTarget.style.color = 'var(--primary)';
                e.currentTarget.style.transform = 'translateY(-1px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = 'var(--surface)';
                e.currentTarget.style.borderColor = 'var(--border)';
                e.currentTarget.style.color = 'var(--text-primary)';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              <span>{a.icon}</span>
              {a.label}
            </Link>
          ))}
        </div>
      </Card>
    </>
  );
}
